def style_ax(fig, ax):
    fig.patch.set_facecolor("#FDFAF5")
    ax.set_facecolor("#F8F4EC")
    for spine in ["top","right"]:
        ax.spines[spine].set_visible(False)
    ax.spines["left"].set_color(OXFORD)
    ax.spines["bottom"].set_color(OXFORD)
    ax.tick_params(colors=OXFORD, labelsize=9)
    ax.xaxis.label.set_color(OXFORD)
    ax.yaxis.label.set_color(OXFORD)
    ax.title.set_color(OXFORD)


# ===============================================================================
#  MODEL LIBRARY - 40+ MODELS
# ===============================================================================
# Each entry: (function, p0_list, param_names, equation_str, reference, category)

def _clip(x, lo=0, hi=100):
    return float(np.clip(x, lo, hi))

# -- BASIC MODELS --------------------------------------------------------------
def m_zero_order(t, k0):
    return k0 * t

def m_first_order(t, k1):
    return 100.0 * (1 - np.exp(-k1 * t))

def m_higuchi(t, kH):
    return kH * np.sqrt(np.abs(t))

def m_hixson_crowell(t, ks):
    inner = 1.0 - ks * t / 3.0
    return np.clip(100.0 * (1 - np.sign(inner) * np.abs(inner) ** 3), 0, 100)

def m_korsmeyer_peppas(t, k, n):
    return k * np.abs(t) ** n

def m_hopfenberg(t, kHB, n_HB):
    return np.clip(100.0 * (1.0 - (1.0 - kHB * t) ** n_HB), 0, 100)

def m_baker_lonsdale(t, kBL):
    results = []
    for ti in np.atleast_1d(t):
        rhs = float(kBL * ti)
        def eq(F):
            F = float(F[0])
            return [1.5 * (1 - (1 - F) ** (2/3)) - F - rhs]
        try:
            sol = root(eq, [0.5], method="hybr")
            results.append(float(np.clip(sol.x[0] * 100, 0, 100)) if sol.success else np.nan)
        except Exception:
            results.append(np.nan)
    return np.array(results)

def m_makoid_banakar(t, kMB, nMB, bMB):
    return kMB * np.abs(t) ** nMB * np.exp(-bMB * t)

def m_peppas_sahlin(t, k1, k2, m):
    return k1 * np.abs(t) ** m + k2 * np.abs(t) ** (2 * m)

def m_weibull(t, a, b, Td):
    t_adj = np.clip(t - Td, 0, None)
    return 100.0 * (1.0 - np.exp(-(t_adj ** b) / a))

def m_gompertz(t, A, b, k):
    return A * np.exp(-b * np.exp(-k * t))

def m_logistic(t, A, k, t50):
    return A / (1.0 + np.exp(-k * (t - t50)))

def m_quadratic(t, a, b, c):
    return a * t**2 + b * t + c

def m_probit(t, mu, sigma, A):
    return A * sp_norm.cdf(t, mu, abs(sigma))

# -- ADVANCED / MODIFIED MODELS ---------------------------------------------
def m_weibull_no_lag(t, a, b):
    return 100.0 * (1.0 - np.exp(-(t ** b) / a))

def m_modified_gompertz(t, Amax, mu, lam):
    return Amax * np.exp(-np.exp(mu * np.e / Amax * (lam - t) + 1))

def m_richards(t, A, k, n, t50):
    return A * (1 + np.exp(-k * (t - t50))) ** (-1/n)

def m_korsmeyer_peppas_lag(t, k, n, tlag):
    t_adj = np.clip(t - tlag, 0, None)
    return k * t_adj ** n

def m_first_order_lag(t, k1, tlag):
    t_adj = np.clip(t - tlag, 0, None)
    return 100.0 * (1 - np.exp(-k1 * t_adj))

def m_zero_order_lag(t, k0, tlag):
    t_adj = np.clip(t - tlag, 0, None)
    return k0 * t_adj

def m_higuchi_lag(t, kH, tlag):
    t_adj = np.clip(t - tlag, 0, None)
    return kH * np.sqrt(t_adj)

def m_double_exponential(t, A1, k1, A2, k2):
    return A1 * (1 - np.exp(-k1 * t)) + A2 * (1 - np.exp(-k2 * t))

def m_triple_exponential(t, A1, k1, A2, k2, A3, k3):
    return (A1 * (1 - np.exp(-k1 * t))
            + A2 * (1 - np.exp(-k2 * t))
            + A3 * (1 - np.exp(-k3 * t)))

def m_power_exponential(t, A, k, n):
    return A * (1 - np.exp(-k * t ** n))

def m_brody(t, A, k, b):
    return A * (1 - b * np.exp(-k * t))

def m_bertalanffy(t, A, k, n):
    return A * (1 - np.exp(-k * t)) ** n

def m_gallagher_corrigan(t, Amax, k1, k2, tmax):
    return Amax * (1 - np.exp(-k1 * t)) - (Amax - 100) * (1 - np.exp(-k2 * np.clip(t - tmax, 0, None)))

def m_logistic_4p(t, A, B, k, t50):
    return A + (B - A) / (1 + np.exp(-k * (t - t50)))

def m_log_normal(t, mu, sigma, A):
    t_safe = np.where(t > 0, t, 1e-9)
    return A * sp_norm.cdf(np.log(t_safe), mu, abs(sigma))

def m_hill(t, Amax, k, n):
    tn = np.abs(t) ** n
    return Amax * tn / (k**n + tn)

def m_weibull_3p(t, alpha, beta, gamma):
    t_adj = np.clip(t - gamma, 0, None)
    return 100.0 * (1.0 - np.exp(-((t_adj / alpha) ** beta)))

def m_exponential_association(t, A, k):
    return A * (1 - np.exp(-k * t))

def m_hyperbolic(t, Amax, k):
    return Amax * t / (k + t)

def m_linear_exponential(t, A, k, b):
    return A * t * np.exp(-k * t) + b

def m_dose_response(t, Emin, Emax, EC50, n):
    tn = np.abs(t) ** n
    return Emin + (Emax - Emin) * tn / (EC50**n + tn)

def m_combined_higuchi_first(t, kH, k1, alpha):
    return alpha * kH * np.sqrt(np.abs(t)) + (1 - alpha) * 100 * (1 - np.exp(-k1 * t))

def m_pade(t, a0, a1, b1):
    return (a0 + a1 * t) / (1 + b1 * t)

def m_hPLC(t, A, B, n):
    return 100 * (1 - (1 + A * t ** n) ** (-B))

def m_compreg(t, k, n, m):
    return 100 * (1 - np.exp(-k * t**n)) ** m

def m_biexponential_absorption(t, F, ka, k):
    return F * 100 * (ka / (ka - k)) * (np.exp(-k * t) - np.exp(-ka * t))

def m_makoid_banakar_mod(t, k, n, b, c):
    return k * np.abs(t)**n * np.exp(-b * t) + c

def m_probit_log(t, mu, sigma, A):
    t_safe = np.where(t > 0, t, 1e-9)
    return A * sp_norm.cdf(np.log10(t_safe), mu, abs(sigma))

def m_henriksen(t, A, k1, k2):
    return A * (np.exp(-k1 * t) - np.exp(-k2 * t))

def m_kpmod(t, k, n, b):
    return k * np.abs(t)**n / (1 + b * t)

def m_fractal_first_order(t, k, alpha):
    return 100.0 * (1 - np.exp(-k * t**alpha))

def m_stretched_exponential(t, A, beta, tau):
    return A * (1 - np.exp(-((t / tau)**beta)))

def m_weibull_sigmoid(t, A, k, t50, b):
    return A / (1 + np.exp(-k * (t - t50))) * (1 - np.exp(-(t/b)**2))

def m_beta_dist_dissolution(t, A, alpha, beta_p):
    from scipy.special import betainc, beta as beta_fn
    t_norm = np.clip(t / t.max() if t.max() > 0 else t, 1e-9, 1-1e-9)
    return A * betainc(alpha, beta_p, t_norm)

