        ws.write("A4", "Generated by DissolvA v2.0 | Powered by AI", fmt_note)

        # Raw data
        ws2 = wb.add_worksheet("Dissolution Profiles")
        col = 0
        for nm, dd in st.session_state.profiles.items():
            ws2.write(0, col, nm, fmt_sub)
            ws2.write(1, col,   f"Time ({time_unit})", fmt_header)
            ws2.write(1, col+1, "Release (%)",          fmt_header)
            for ri,(ti,ri_v) in enumerate(zip(dd["time"],dd["release"])):
                ws2.write(ri+2, col,   ti,   fmt_data)
                ws2.write(ri+2, col+1, ri_v, fmt_data)
            ws2.set_column(col, col+1, 14)
            col += 3

        # Statistics
        ws3 = wb.add_worksheet("Statistics")
        ws3.write(0,0,"Statistical Summary",fmt_title)
        hdrs = [f"Time ({time_unit})","Profile","Release (%)","MDT","DE (%)"]
        for ci,h in enumerate(hdrs):
            ws3.write(1,ci,h,fmt_header)
            ws3.set_column(ci,ci,16)
        ri2 = 2
        for nm, dd in st.session_state.profiles.items():
            ta = np.array(dd["time"]); ra = np.array(dd["release"])
            mdt = compute_mdt(ta,ra); de = compute_de(ta,ra)
            for ti,rv in zip(ta,ra):
                ws3.write(ri2,0,ti,fmt_data)
                ws3.write(ri2,1,nm,fmt_plain)
                ws3.write(ri2,2,rv,fmt_data)
                ws3.write(ri2,3,round(mdt,3) if not np.isnan(mdt) else "N/A",fmt_plain)
                ws3.write(ri2,4,round(de,3),fmt_data)
                ri2 += 1

        # Model Fitting
        ws4 = wb.add_worksheet("Model Fitting")
        ws4.write(0,0,"Kinetic Model Fitting Results",fmt_title)
        fh = ["Model","Category","R2","R2adj","AIC","MSC","Params","Parameters","Reference"]
        for ci,h in enumerate(fh):
            ws4.write(1,ci,h,fmt_header)
        ws4.set_column(0,0,26); ws4.set_column(1,1,14); ws4.set_column(7,7,45); ws4.set_column(8,8,30)

        if st.session_state.fit_results:
            sorted_r = sorted(
                [(k,v) for k,v in st.session_state.fit_results.items() if v["success"]],
                key=lambda x: x[1]["r2adj"], reverse=True
            )
            for ri3,(mn,v) in enumerate(sorted_r):
                row = ri3+2
                adj = v["r2adj"]
                ws4.write(row,0,mn,fmt_plain)
                ws4.write(row,1,v["category"],fmt_plain)
                ws4.write(row,2,round(v["r2"],4),fmt_data)
                ws4.write(row,3,round(adj,4),fmt_good if adj>=0.9 else fmt_bad)
                ws4.write(row,4,round(v["aic"],3),fmt_data)
                ws4.write(row,5,round(v["msc"],3),fmt_data)
                ws4.write(row,6,v["n_params"],fmt_plain)
                pstr = "; ".join(f"{k}={pv:.4g}" for k,pv in v["params"].items())
                ws4.write(row,7,pstr,fmt_plain)
                ws4.write(row,8,v["reference"],fmt_plain)

        wb.close()
        buf.seek(0)
        st.success("Report ready!")
        st.download_button(
            "Download Excel Report",
            data=buf.getvalue(),
            file_name="DissolvA_Report.xlsx",
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
        )
